codeExample:
// Assuming XML Response:
// <company>
//   <employee id="101">
//     <name>Jane Doe</name>
//   </employee>
// </company>

given().
    accept(ContentType.XML).
when().
    get("/company/xml").
then().
    statusCode(200).
    // Validate text node
    body("company.employee.name", equalTo("Jane Doe")).
    // Validate attribute
    body("company.employee.@id", equalTo("101"));
